226→    const storedWidth = res?.geminiChatWidth;
227→    const numericStoredWidth = typeof storedWidth === 'number' ? storedWidth : DEFAULT_PERCENT;
228→    const normalized = normalizePercent(numericStoredWidth, DEFAULT_PERCENT);
229→    currentWidthPercent = normalized;
230→    enabled = res?.[ENABLED_KEY] === true;
231→
232→    if (enabled) {
233→      applyWidth(currentWidthPercent);
234→    }
235→
236→    if (typeof storedWidth === 'number' && storedWidth !== normalized) {
237→      try {
238→        chrome.storage?.sync?.set({ geminiChatWidth: normalized });
239→      } catch (e) {
240→        console.warn('[Gemini Voyager] Failed to migrate chat width to %:', e);
241→      }
242→    }
243→  });
244→
245→  // Listen for changes from storage
246→  const storageChangeHandler = (
247→    changes: Record<string, chrome.storage.StorageChange>,
248→    area: string,
249→  ) => {
250→    if (area !== 'sync') return;
251→
252→    if (changes[ENABLED_KEY]) {
253→      enabled = changes[ENABLED_KEY].newValue === true;
254→      if (enabled) {
255→        applyWidth(currentWidthPercent);
256→      } else {
257→        removeStyles();
258→      }
259→    }
260→
261→    if (changes.geminiChatWidth) {
262→      const newWidth = changes.geminiChatWidth.newValue;
263→      if (typeof newWidth === 'number') {
264→        const normalized = normalizePercent(newWidth, DEFAULT_PERCENT);
265→        currentWidthPercent = normalized;
266→        if (enabled) {
267→          applyWidth(currentWidthPercent);
268→        }
269→
270→        if (normalized !== newWidth) {
271→          try {
272→            chrome.storage?.sync?.set({ geminiChatWidth: normalized });
273→          } catch (e) {
274→            console.warn('[Gemini Voyager] Failed to migrate chat width to % on change:', e);
275→          }
276→        }
277→      }
278→    }
279→  };
280→
281→  chrome.storage?.onChanged?.addListener(storageChangeHandler);
282→
283→  // Re-apply styles when DOM changes (for dynamic content)
284→  // Use debouncing and cache the width to avoid storage reads
285→  let debounceTimer: number | null = null;
286→  const observer = new MutationObserver(() => {
287→    if (debounceTimer !== null) {
288→      clearTimeout(debounceTimer);
289→    }
290→    debounceTimer = window.setTimeout(() => {
291→      if (enabled) {
292→        applyWidth(currentWidthPercent);
293→      }
294→      debounceTimer = null;
295→    }, 200);
296→  });
