301→    observer.observe(main, {
302→      childList: true,
303→      subtree: true,
304→    });
305→  }
306→
307→  // Clean up on unload to prevent memory leaks
308→  window.addEventListener(
309→    'beforeunload',
310→    () => {
311→      observer.disconnect();
312→      removeStyles();
313→      // Remove storage listener
314→      try {
315→        chrome.storage?.onChanged?.removeListener(storageChangeHandler);
316→      } catch (e) {
317→        console.error('[Gemini Voyager] Failed to remove storage listener on unload:', e);
318→      }
