  window.addEventListener(
    'beforeunload',
    () => {
      observer.disconnect();
      removeStyles();
      // Remove storage listener
      try {
        chrome.storage?.onChanged?.removeListener(storageChangeHandler);
      } catch (e) {
        console.error('[Gemini Voyager] Failed to remove storage listener on unload:', e);
      }
    },
    { once: true },
  );
}

